// 1. SAFE INPUT EXTRACTION
// 1. SMART INPUT EXTRACTION
// This block handles every way n8n might send the data (String, Object, or Nested)
let rawInput;

// Try to grab the variable 'query'
try { rawInput = query; } catch (e) {
    try { rawInput = inputs.query; } catch(e2) {
        try { rawInput = input.query; } catch(e3) {
             try { rawInput = $input.first().json.query; } catch(e4) {}
        }
    }
}

// If it's an object (which caused your error), drill down to find the text
if (typeof rawInput === 'object' && rawInput !== null) {
    if (rawInput.query) rawInput = rawInput.query;
    else if (rawInput.specialization) rawInput = rawInput.specialization;
    // Fallback: If we can't find a property, stringify it so we see the JSON in the error
    else rawInput = JSON.stringify(rawInput);
}

// 2. VALIDATION
if (!rawInput) {
    return JSON.stringify({ error: "No input found. Test with JSON: { \"query\": \"Dermatologist\" }" });
}

// Clean up the search term
let targetSpec = String(rawInput);
// Fix for double-quotes if they appear (e.g. ""Dermatologist"")
if (targetSpec.startsWith('"') && targetSpec.endsWith('"')) {
    targetSpec = targetSpec.slice(1, -1);
}
targetSpec = targetSpec.toLowerCase().trim();


// 3. GET DOCTOR LIST
let allDoctorItems;
try {
    // Ensure this matches your node name
    allDoctorItems = $('Get row(s) in sheet').all();
} catch (error) {
    return JSON.stringify({ error: "CRITICAL: Could not find node 'Get row(s) in sheet'." });
}

// 4. RUN SEARCH
const matchedItem = allDoctorItems.find(item => {
    const doc = item.json;
    const spec = doc["Specialization"];
    const avail = doc["Availability"];

    // Logic: Match Specialization AND check 'Available'
    return spec && spec.toLowerCase().trim() === targetSpec && 
           avail && avail.toLowerCase().includes("available");
});

// 5. RETURN RESULT
if (matchedItem) {
    return JSON.stringify(matchedItem.json);
} else {
    // Debug info
    const availableSpecs = allDoctorItems.map(i => `${i.json["Specialization"]} (${i.json["Availability"]})`).slice(0, 10).join(", ");
    return JSON.stringify({
        status: "NO MATCH",
        you_asked_for: targetSpec,
        sheet_contains_preview: availableSpecs
    });
}

